"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["7604"],{40871(e,a,o){o.r(a),o.d(a,{default:()=>r});var t=o(74848),s=o(47643),i=JSON.parse('{"id":259,"es":{"title":"Correspondencia de diarios","prompt":"I want you to act as a scientific manuscript matcher. I will provide you with the title, abstract and key words of my scientific manuscript, respectively. Your task is analyzing my title, abstract and key words synthetically to find the most related, reputable journals for potential publication of my research based on an analysis of tens of millions of citation connections in database, such as Web of Science, Pubmed, Scopus, ScienceDirect and so on. You only need to provide me with the 15 most suitable journals. Your reply should include the name of journal, the cooresponding match score (The full score is ten). Respond in Spanish. I want you to reply in text-based excel sheet and sort by matching scores in reverse order.\\nMy title is \\"XXX\\" My abstract is \\"XXX\\" My key words are \\"XXX\\".","description":"Me gustar\xeda que actuaran como intermediarios para manuscritos cient\xedficos. Le proporcionar\xe9 por separado el t\xedtulo, el resumen y las palabras clave de mi manuscrito cient\xedfico. Su tarea consiste en sintetizar mi t\xedtulo, resumen y palabras clave para encontrar las revistas m\xe1s relevantes y reputadas para mi investigaci\xf3n a partir del an\xe1lisis de decenas de millones de enlaces de citas en bases de datos, como Web of Science, Pubmed, Scopus, ScienceDirect, etc\xe9tera. Todo lo que tiene que hacer es proporcionarme las 15 revistas m\xe1s apropiadas. Su respuesta debe incluir el nombre de la revista y la correspondiente puntuaci\xf3n de coincidencia sobre 10. Me gustar\xeda que me respondiera en una hoja de c\xe1lculo Excel basada en texto, ordenada en orden inverso por puntuaci\xf3n de coincidencia.","remark":"Contribuci\xf3n de @ScenerorSun, citado en el sitio B @Yams Potpourri."},"tags":["contribute","write"],"website":null,"count":1746,"related":[{"id":197,"title":"Toques de naturaleza","remark":"Se retocar\xe1 al estilo Nature, o se puede aportar un estilo de escritura que se quiera emular. Contribuci\xf3n de @Pfyuan77."},{"id":204,"title":"gui\xf3n oral","remark":"Guionizaci\xf3n de v\xeddeos, retransmisiones en directo, podcasts, pantalla dividida y otros contenidos hablados. Lanzamiento de @bettycroco."},{"id":256,"title":"Robot generador de art\xedculos","remark":"Producci\xf3n personalizada de art\xedculos desde m\xfaltiples perspectivas, con buena estabilidad. Ocasionalmente salidas reglas, que se pueden ajustar haciendo clic en regenerar, y el formato de palabra prompt se refiere a Mr.-Ranedeer-AI-Tutor. contribuci\xf3n de @snowMan0622."}],"metaTitle":"Buscador de Revistas","metaDescription":"\xbfQu\xe9 revista? Encuentre las mejores opciones para su paper. 15 recomendaciones por relevancia. \xa1Pru\xe9balo!","faq":[{"q":"\xbfExisten realmente las revistas que recomienda?","a":"Las principales (Nature, Cell, PNAS) s\xed; en subcampos inventa o usa datos viejos. Los factores de impacto y tiempos de revisi\xf3n tambi\xe9n pueden ir desactualizados. Verifica en JCR, Scimago o la web oficial de la revista."},{"q":"\xbfEl factor de impacto es actual?","a":"No; usa el dato anterior a su fecha de corte, puede ir 1-2 a\xf1os desfasado. JCR se actualiza en junio; para el IF actual, usa Web of Science. Toma los n\xfameros de la IA como orden de magnitud; no los cites en informes formales."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,t.jsx)(s.A,{prompt:i,currentLanguage:"es"})}}}]);